mapper.select:
SELECT p.*, u.id as seller_user_id, u.username as seller_username, u.phone as seller_phone, u.avatar as seller_avatar, c.name as category_name, (SELECT url FROM image WHERE product_id = p.id ORDER BY sort_order ASC LIMIT 1) as first_image_url FROM product p LEFT JOIN `user` u ON p.seller_id = u.id LEFT JOIN category c ON p.category_id = c.id
AND p.title LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}
AND p.status = #{status}
ORDER BY p.created_at DESC

SELECT p.*, (SELECT url FROM image WHERE product_id = p.id ORDER BY sort_order ASC LIMIT 1) as first_image_url FROM product p WHERE seller_id = #{sellerId} AND status != 4
AND status = #{status}
ORDER BY created_at DESC

SELECT p.*, u.id as seller_user_id, u.username as seller_username, u.phone as seller_phone, u.avatar as seller_avatar, c.name as category_name, (SELECT url FROM image WHERE product_id = p.id ORDER BY sort_order ASC LIMIT 1) as first_image_url FROM product p LEFT JOIN `user` u ON p.seller_id = u.id LEFT JOIN category c ON p.category_id = c.id WHERE p.status = 1
AND p.title LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}
ORDER BY p.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM product p WHERE p.status = 1
AND p.title LIKE CONCAT('%', #{keyword}, '%')
AND p.category_id = #{categoryId}

mapper.update:
UPDATE product SET status = #{status},
reject_reason = #{rejectReason}, reject_reason = NULL,
updated_at = NOW() WHERE id = #{id}
